const posts = $('Prepare data').first().json.posts

if (
    Array.isArray(posts) &&
    posts.every(item => typeof item === 'object' && item !== null && !Array.isArray(item))
  ) {
    return posts;
  }

return { "json": {} };

const output = $input.first().json.output;

const cleaned = output.replace(/```json\n?/, '')
    .replace(/```$/, '')
    .trim();

const data = JSON.parse(cleaned);

return {data}

const model =  $('Prepare data').first().json.model;
const callback = $vars.SAAS_API + '/api/social-agent/process';
const obj = JSON.parse($input.first().json.content.parts[0].text);
const prompt = obj.prompt;

if(model == 'veo3_fast'){
  return {
    "url": "https://api.kie.ai/api/v1/veo/generate",
    "config": {
      "prompt": prompt,
      "model": model,
      "callBackUrl": callback,
      "aspectRatio": "9:16",
      "imageUrls": [
        $('HTTP Request').first().json.image
      ]
    } 
  }
}else if(model == 'runway-duration-10-generate'){
  return {
    "url": "https://api.kie.ai/api/v1/runway/generate",
    "config": {
      "prompt": prompt,
      "model": model,
      "callBackUrl": callback,
      "aspectRatio": "9:16",
      "quality": "720p",
      "duration": "10",
      "imageUrl": $('HTTP Request').first().json.image
    } 
  }

}else if(model == 'sora-2-text-to-video'){
  return {
    url: "https://api.kie.ai/api/v1/jobs/createTask",
    config: {
      //"model": model,
      "model": "sora-2-image-to-video",
      "callBackUrl": callback,
      "input":{
        "prompt": prompt,
        "image_urls": [$('HTTP Request').first().json.image],
        "aspect_ratio": "portrait",
        "n_frames": "15",
        "remove_watermark": true
      }
    }
  }
}else if(model == 'kling-2.6/image-to-video'){
  return {
    url: "https://api.kie.ai/api/v1/jobs/createTask",
    config: {
      "model": model,
