      "input":{
        "prompt": prompt,
        "image_urls": [
          $('HTTP Request').first().json.image
        ],
        "sound": false,
        "duration": "10"
      }
    }
  }
}else if(model == 'bytedance/seedance-1.5-pro'){
  return {
